window.ASBAB_NUZUL_CACHE["62"] = {"asbab_nuzul":{"11":[{"ar":"عَنْ جَابِرِ بْنِ عَبْدِ اللهِ رضي الله عنهما قَالَ: أَقْبَلَتْ عِيرٌ يَوْمَ الْجُمُعَةِ، وَنَحْنُ مَعَ النَّبِيِّ ﷺ، فَثَارَ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا، فَأَنْزَلَ الله: { وَإِذَا رَأَوْا۟ تِجَـٰرَةً أَوْ لَهْوًا ٱنفَضُّوٓا۟ إِلَيْهَا وَتَرَكُوكَ قَآئِمًا ۚ }. واللفظ للبخاري.","id":""}]},"mapping_ayat":{"62:3":[{"p":"Tirmidzi","n":3061,"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَنِي ثَوْرُ بْنُ زَيْدٍ الدِّيْلِيُّ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ سُورَةُ الْجُمُعَةِ فَتَلَاهَا فَلَمَّا بَلَغَ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ مَنْ هَؤُلَاءِ الَّذِينَ لَمْ يَلْحَقُوا بِنَا فَلَمْ يُكَلِّمْهُ قَالَ وَسَلْمَانُ الْفَارِسِيُّ فِينَا قَالَ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَلْمَانَ يَدَهُ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ كَانَ الْإِيمَانُ بِالثُّرَيَّا لَتَنَاوَلَهُ رِجَالٌ مِنْ هَؤُلَاءِثَوْرُ بْنُ زَيْدٍ مَدَنِيٌّ وَثَوْرُ بْنُ يَزِيدَ شَامِيٌّ وَأَبُو الْغَيْثِ اسْمُهُ سَالِمٌ مَوْلَى عَبْدِ اللَّهِ بْنِ مُطِيعٍ مَدَنِيٌّ ثِقَةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَعَبْدُ اللَّهِ بْنُ جَعْفَرٍ هُوَ وَالِدُ عَلِيِّ بْنِ الْمَدِينِيِّ ضَعَّفَهُ يَحْيَى بْنُ مَعِينٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ","trj":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Abdullah bin Ja'far] telah menceritakan kepadaku [Tsaur bin Zaid Ad Dili] dari [Abu Al Ghaits] dari [Abu Hurairah], ia berkata; kami berada di sisi Rasulullah shallallahu 'alaihi wasallam ketika telah diturunkan Surat Al Jumu'ah, kemudian beliau membacanya. Tatkala beliau telah sampai pada perkataan: \"Dan (juga) kepada kaum yang lain dari mereka yang belum berhubungan dengan mereka. Dan Dia-lah Yang Maha Perkasa lagi Maha Bijaksana.\" (QS. Aljumah 3), Seorang laki-laki berkata; wahai Rasulullah, siapakah mereka yang belum berhubungan dengan kita? Kemudian beliau tidak menjawab sementara Salman Al Farisi bersama kami. Abu Hurairah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya kepada Salman dan berkata: \"Demi Dzat yang jiwaku ada di tanganNya, seandainya keimanan itu berada di gugusan bintang, niscaya akan diambil oleh orang-orang. Diantara mereka adalah Tsaur bin Zaid Madani, dan Tsaur bin Yazid Syami, Abu Al Ghaits namanya adalah Salim mantan budak Abdullah bin Muthi' Madani, yang ia adalah orang yang tsiqah.\" Abu Isa berkata; hadits ini adalah hadits gharib, dan Abdullah bin Ja'far adalah ayah Ali bin Al Madini, ia telah didha'ifkan oleh Yahya bin Ma'in. Dan hadits ini telah diriwayatkan dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dari selain sisi ini."}],"62:5":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"62:8":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"62:9":[{"p":"Malik","n":219,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك أَنَّهُ سَأَلَ ابْنَ شِهَابٍعَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا نُودِيَ لِلصَّلَاةِ مِنْ يَوْمِ الْجُمُعَةِ فَاسْعَوْا إِلَى ذِكْرِ اللَّهِ }فَقَالَ ابْنُ شِهَابٍ كَانَ عُمَرُ بْنُ الْخَطَّابِ يَقْرَؤُهَا إِذَا نُودِيَ لِلصَّلَاةِ مِنْ يَوْمِ الْجُمُعَةِ فَامْضُوا إِلَى ذِكْرِ اللَّهِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dia bertanya kepada [Ibnu Syihab] tentang firman Allah Azza Wa Jalla: '(Wahai orang-orang yang beriman, apabila kalian dipanggil untuk shalat di hari Jumat maka bersegerlah menuju dzikir kepada Allah..) \" Qs. Al Jumu'ah: 9) Ibnu Syihab berkata; \" [Umar bin Al Khattahab] membacanya dengan; 'Apabila kalian dipanggil untuk shalat maka berlalulah menuju Dzikir kepada Allah'.\""}],"62:11":[{"p":"Bukhari","n":4214,"ar":"حَدَّثَنِي حَفْصُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ وَعَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقْبَلَتْ عِيرٌ يَوْمَ الْجُمُعَةِ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَثَارَ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا فَأَنْزَلَ اللَّهُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah menceritakan kepadaku [Hafsh bin Umar] Telah menceritakan kepada kami [Khalid bin Abdullah] Telah menceritakan kepada kami [Hushain] dari [Salim bin Abul Ja'dari] dan dari [Abu Sufyan] dari [Jabir bin Abdullah radliallahu 'anhuma] ia berkata; Pada hari Jum'at, datanglah barang dagangan sementara kami saat itu sedang bersama Nabi shallallahu 'alaihi wasallam. Maka orang-orang pun pergi kecuali dua belas orang yang tersisa, maka Allah menurunkan ayat: \"Dan ketika mereka melihat perdagangan atau kesenangan mereka bergegas padanya dan meninggalkanmu dalam keadaan berdiri (menyampaikan khuthbah).\" (QS. Aljumu'ah 11)."},{"p":"Nasa'i","n":1371,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَدَخَلَ الْمَسْجِدَ وَعَبْدُ الرَّحْمَنِ ابْنُ أُمِّ الْحَكَمِ يَخْطُبُ قَاعِدًا فَقَالَ انْظُرُوا إِلَى هَذَا يَخْطُبُ قَاعِدًا وَقَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah mengabarkan kepada kami [Ahmad bin 'Abdullah bin Al Hakam] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari ['Amr bin Murrah] dari [Abu 'Ubaidah] dari [Ka'b bin 'Ujrah] dia berkata; \"Aku masuk ke masjid, dan Abdurrahman bin Ummu Hakam sedang khutbah sambil duduk.\" Lalu Ka'ab berkata; \"Lihatlah orang ini yang sedang khutbah sambil duduk! Padahal Allah Azza wa Jalla berfirman: \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhutbah) '. (Qs. Al Jumu'ah (62): 11).\""}]},"mapping_surah":[{"p":"Abu Dawud","n":936,"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي رَافِعٍ قَالَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ وَفِي الرَّكْعَةِ الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ يَقْرَأُ بِهِمَا بِالْكُوفَةِ قَالَ أَبُو هُرَيْرَةَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا يَوْمَ الْجُمُعَةِ","trj":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Bilal] dari [Ja'far] dari [ayahnya] dari [Ibnu Abu Rafi'] dia berkata; Abu Hurairah shalat mangimami kami pada hari (shalat) Jum'at, lalu dia membaca surat Al Jumuah pada raka'at pertama dan \"idza jaa-akal munafiqun\" pada raka'at terakhir. Selesai shalat, aku menjumpai Abu Hurairah dan berkata kepadanya; \"Sesungguhnya anda membaca surat sebagaimana yang dibaca oleh Ali bin Abu Thalib di Kufah.\" [Abu Hurairah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca kedua surat tersebut pada shalat Jum'at.\""},{"p":"Bukhari","n":884,"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَقْبَلَتْ عِيرٌ تَحْمِلُ طَعَامًا فَالْتَفَتُوا إِلَيْهَا حَتَّى مَا بَقِيَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] berkata, telah menceritakan kepada kami [Za'idah] dari [Hushain] dari [Salim bin Abu Al Ja'd] berkata, telah menceritakan kepada kami [Jabir bin 'Abdullah] berkata, \"Ketika kami sedang shalat bersama Nabi shallallahu 'alaihi wasallam tiba-tiba datang rombongan dagang yang membawa makanan. Orang-orang pun melirik (dan berhamburan pergi) mendatangi rombongan tersebut, hingga tidak ada orang yang tersisa bersama Nabi shallallahu 'alaihi wasallam kecuali hanya dua belas orang. Maka turunlah ayat ini: '(Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhutbah) ' (Qs. Al Jumu'ah: 12)."},{"p":"Bukhari","n":1917,"ar":"حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا زَائِدَةُ عَنْ حُصَيْنٍ عَنْ سَالِمٍ قَالَ حَدَّثَنِي جَابِرٌ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَقْبَلَتْ مِنْ الشَّأْمِ عِيرٌ تَحْمِلُ طَعَامًا فَالْتَفَتُوا إِلَيْهَا حَتَّى مَا بَقِيَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَنَزَلَتْ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا }","trj":"Telah menceritakan kepada kami [Tholq bin Ghonnam] telah menceritakan kepada kami [Za'idah] dari [Hushain] dari [Salim] berkata, telah menceritakan kepada saya [Jabir radliallahu 'anhu] berkata: \"Ketika kami sedang shalat bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba datang rombongan dagang dari negeri Syam yang membawa makanan. Maka orang-orang melirik (dan berhamburan pergi) mendatangi rambongan tersebut, hingga tidak ada orang yang tersisa bersama Nabi shallallahu 'alaihi wasallam kecuali hanya dua belas orang. Maka turunlah ayat ini (QS. Al Jumu'ah ayat 12) yang artinya.: (\"Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhuthbah\". "},{"p":"Bukhari","n":1922,"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقْبَلَتْ عِيرٌ وَنَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ فَانْفَضَّ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah menceritakan kepada saya [Muhammad] berkata, telah menceritakan kepada saya [Muhammad bin Fudhail] dari [Hushain] dari [Salim bin Abu Al Ja'di] dari [Jabir radliallahu 'anhu] berkata: \"Ketika kami sedang shalat Jum'at bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba datang rambongan dagang. Maka orang-orang melirik (dan berhamburan pergi) kecuali hanya dua belas orang. Maka kemudian turunlah ayat ini (QS. Al Jumu'ah ayat 12) yang artinya.: (\"Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhuthbah\". "},{"p":"Bukhari","n":4213,"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُنْزِلَتْ عَلَيْهِ سُورَةُ الْجُمُعَةِ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ قُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ فَلَمْ يُرَاجِعْهُ حَتَّى سَأَلَ ثَلَاثًا وَفِينَا سَلْمَانُ الْفَارِسِيُّ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى سَلْمَانَ ثُمَّ قَالَ لَوْ كَانَ الْإِيمَانُ عِنْدَ الثُّرَيَّا لَنَالَهُ رِجَالٌ أَوْ رَجُلٌ مِنْ هَؤُلَاءِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ الْعَزِيزِ أَخْبَرَنِي ثَوْرٌ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَالَهُ رِجَالٌ مِنْ هَؤُلَاءِ","trj":"Telah menceritakan kepadaku [Abdul Aziz bin Abdullah] ia berkata, Telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Tsaur] dari [Abul Ghaits] dari [Abu Hurairah radliallahu 'anhu] ia berkata; Suatu hari, kami duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu diturunkanlah pada beliau surat Al Jumu'ah dan \"WA `AAKHARIINA MINHUM LAMMAA YALHAQUU BIHIM.\" Maka aku pun bertanya, \"Siapa mereka itu wahai Rasulullah?\" Namun, beliau belum juga menjawab hingga tiga orang bertanya. Di antara kami ada Salman Al Farisi. Kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya pada Salman dan bersabda: \"Sekiranya keimanan itu ada di gugusan bintang, niscaya keimanan itu tetap akan diperoleh oleh sekelompok atau seseorang dari mereka itu (Orang-orang Persi).\" Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] Telah menceritakan kepada kami [Abdul Aziz] Telah mengabarkan kepadaku [Tsaur] dari [Abul Ghaits] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Niscaya (keimanan) itu akan diperoleh oleh sekelompok orang dari mereka (Orang Persi).\""},{"p":"Bukhari","n":4214,"ar":"حَدَّثَنِي حَفْصُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ وَعَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقْبَلَتْ عِيرٌ يَوْمَ الْجُمُعَةِ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَثَارَ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا فَأَنْزَلَ اللَّهُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah menceritakan kepadaku [Hafsh bin Umar] Telah menceritakan kepada kami [Khalid bin Abdullah] Telah menceritakan kepada kami [Hushain] dari [Salim bin Abul Ja'dari] dan dari [Abu Sufyan] dari [Jabir bin Abdullah radliallahu 'anhuma] ia berkata; Pada hari Jum'at, datanglah barang dagangan sementara kami saat itu sedang bersama Nabi shallallahu 'alaihi wasallam. Maka orang-orang pun pergi kecuali dua belas orang yang tersisa, maka Allah menurunkan ayat: \"Dan ketika mereka melihat perdagangan atau kesenangan mereka bergegas padanya dan meninggalkanmu dalam keadaan berdiri (menyampaikan khuthbah).\" (QS. Aljumu'ah 11)."},{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "},{"p":"Darimi","n":1167,"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍ الْأَنْصَارِيَّ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ قَالَ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","trj":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Adl Dlahhak bin Qais] bertanya kepada [An Nu'man bin Basyir Al Anshari], \"Apa yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at setelah surat Al Jumu'ah?\" Ia menjawab, \"HAL ATAAKA HADIITSUL QHAASYIYAH (surat Al Insaan).\""},{"p":"Ibnu Majah","n":1075,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ الْمَدَنِيُّ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ قَالَاسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ فَخَرَجَ إِلَى مَكَّةَ فَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ فِي السَّجْدَةِ الْأُولَى وَفِي الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ عُبَيْدُ اللَّهِ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيٌّ يَقْرَأُ بِهِمَا بِالْكُوفَةِ فَقَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il Al Madani] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ubaidullah bin Abu Rafi'] ia berkata, \"Marwan mewakilkan kota Madinah kepada Abu Hurairah, pada suatu hari ia keluar menuju Makkah, kemudian di hari jum'at Abu Hurairah shalat bersama kami. Ia membaca surat Al Jumu'ah di raka'at pertama dan membaca IDZAA JAA`AKAL MUNAAFIQUUN di raka'at terakhir. \" Ubaidullah berkata, \"Ketika Abu Hurairah berlalu pergi aku menjumpainya dan bertanya, \"Engkau membaca dua surat yang pernah Ali baca di Kufah?\" [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca keduanya. \" "},{"p":"Ibnu Majah","n":1076,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ أَنْبَأَنَا ضَمْرَةُ بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَكَتَبَ الضَّحَّاكُ بْنُ قَيْسٍ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ أَخْبِرْنَا بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ مَعَ سُورَةِ الْجُمُعَةِ قَالَ كَانَ يَقْرَأُ فِيهَا هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","trj":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] berkata, telah memberitakan kepada kami [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah] berkata; Adl Dlahhak bin Qais menulis surat kepada [An Nu'man bin Basyir]; kabarkanlah kepada kami surat apa yang di baca Rasulullah shallallahu 'alaihi wasallam pada hari jum'at, selain surat Al Jumu'ah?\" ia menjawab, \"Di hari jum'at beliau membaca HAL ATAAKA HADIITSUL GHAASYIAH (Sudah datangkah kepadamu berita (tentang) hari pembalasan?) \""},{"p":"Malik","n":219,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك أَنَّهُ سَأَلَ ابْنَ شِهَابٍعَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا نُودِيَ لِلصَّلَاةِ مِنْ يَوْمِ الْجُمُعَةِ فَاسْعَوْا إِلَى ذِكْرِ اللَّهِ }فَقَالَ ابْنُ شِهَابٍ كَانَ عُمَرُ بْنُ الْخَطَّابِ يَقْرَؤُهَا إِذَا نُودِيَ لِلصَّلَاةِ مِنْ يَوْمِ الْجُمُعَةِ فَامْضُوا إِلَى ذِكْرِ اللَّهِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dia bertanya kepada [Ibnu Syihab] tentang firman Allah Azza Wa Jalla: '(Wahai orang-orang yang beriman, apabila kalian dipanggil untuk shalat di hari Jumat maka bersegerlah menuju dzikir kepada Allah..) \" Qs. Al Jumu'ah: 9) Ibnu Syihab berkata; \" [Umar bin Al Khattahab] membacanya dengan; 'Apabila kalian dipanggil untuk shalat maka berlalulah menuju Dzikir kepada Allah'.\""},{"p":"Malik","n":225,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍمَاذَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ قَالَ كَانَ يَقْرَأُ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Dlamrah bin Sa'id Al-Mazini] dari [Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud], bahwa Ad Dlahhak bin Qais bertanya kepada [Nu'man bin Basyir], \"Apa yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari Jumat setelah surat Al Jumu'ah?\" dia menjawab; \"Beliau membaca: \"HAL ATAAKA HADITSUL GHASYIYAH.\""},{"p":"Muslim","n":1347,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ جَرِيرٍ قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ حُصَيْن�� بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ قَائِمًا يَوْمَ الْجُمُعَةِ فَجَاءَتْ عِيرٌ مِنْ الشَّامِ فَانْفَتَلَ النَّاسُ إِلَيْهَا حَتَّى لَمْ يَبْقَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَأُنْزِلَتْ هَذِهِ الْآيَةُ الَّتِي فِي الْجُمُعَةِ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ بِهَذَا الْإِسْنَادِ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَلَمْ يَقُلْ قَائِمًا","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] keduanya dari [Jarir] - [Utsman] berkata- telah menceritakan kepada kami [Jarir] dari [Hushain bin Abdurrahman] dari [Salim bin Abul Ja'd] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam menyampaikan khutbah dengan berdiri pada hari Jum'at, tiba-tiba datanglah suatu Kafilah dagang dari negeri Syam; maka jama'ah pun berlarian menjemput Kafilah itu, hingga yang tinggal di Masjid hanya dua belas orang lagi. Maka diturunkanlah ayat ini (yakni pada surat Al Jumu'ah): \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhutbah).\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dengan isnad ini, ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah. -ia tidak mengatakan; berdiri."},{"p":"Muslim","n":1369,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي رَافِعٍ قَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ وَخَرَجَ إِلَى مَكَّةَ فَصَلَّى لَنَا أَبُو هُرَيْرَةَ الْجُمُعَةَ فَقَرَأَ بَعْدَ سُورَةِ الْجُمُعَةِ فِي الرَّكْعَةِ الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيُّ بْنُ أَبِي طَالِبٍ يَقْرَأُ بِهِمَا بِالْكُوفَةِفَقَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا يَوْمَ الْجُمُعَةِو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ كِلَاهُمَا عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ قَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ بِمِثْلِهِ غَيْرَ أَنَّ فِي رِوَايَةِ حَاتِمٍ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ فِي السَّجْدَةِ الْأُولَى وَفِي الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ وَرِوَايَةُ عَبْدِ الْعَزِيزِ مِثْلُ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","trj":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Ja'far] dari [bapaknya] dari [Ibnu Abu Rafi'] ia berkata; Suatu ketika (khalifah) Marwan meminta kepada [Abu Hurairah] untuk menggantikannya (sebagai pemimpin) di Madinah, sementara Marwan pergi ke Makkah. Maka pada suatu hari Jum'at, Abu Hurairah mengimami kami shalat Jum'at. Ia membaca surat Al Jumu'ah pada raka'at pertama, dan surat Al Munafiqun pada raka'at kedua. Setelah selesai shalat, kutemui Abu Hurairah dan kukatakan kepadanya, \"Kedua surat yang Anda baca tadi, pernah dibaca oleh Ali bin Abi Thalib ketika ia berada di Kufah.\" Abu Hurairah berkata, \"Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam membaca kedua surat itu pada hari Jum'at.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakar bin Abu Syaibah] keduanya berkata, telah menceritakan kepada kami [Hatim bin Isma'il] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz] yakni Ad Darawardi, keduanya dari [Ja'far] dari [bapaknya] dari [Ubaidullah bin Abu Rafi'] ia berkata; Marwan meminta kepada [Abu Hurairah] untuk menggantikannya. Yakni semisalnya. Hanya saja dalam riwayat Hatim; \"Maka ia pun membaca surat Al Jumu'ah pada sujud yang pertama, sedangkan pada sujud (raka'at) terakhir ia membaca, 'IDZAA JAA`AKAL MUNAAFIQUUNA..'\" Sedangkan pada riwayat Abdul Aziz adalah serupa dengan hadits Sulaiman bin Bilal."},{"p":"Muslim","n":1371,"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَكَتَبَ الضَّحَّاكُ بْنُ قَيْسٍ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ يَسْأَلُهُ أَيَّ شَيْءٍ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ سِوَى سُورَةِ الْجُمُعَةِ فَقَالَ كَانَ يَقْرَأُ هَلْ أَتَاكَ","trj":"Dan Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah] ia berkata, Adl Dlahak bin Qais menulis surat kepada [An Nu'man bin Basyir] menanyakan tentang surat yang apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at selain surat Jumu'ah. Maka ia menjawab, \"Beliau membaca surat Al Ghasyiah.\""},{"p":"Muslim","n":1372,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سُفْيَانَ عَنْ مُخَوَّلِ بْنِ رَاشِدٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْفَجْرِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ السَّجْدَةِ وَهَلْ أَتَى عَلَى الْإِنْسَانِ حِينٌ مِنْ الدَّهْرِ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ سُورَةَ الْجُمُعَةِ وَالْمُنَافِقِينَو حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ كِلَاهُمَا عَنْ سُفْيَانَ بِهَذَا الْإِسْنَادِ مِثْلَهُ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُخَوَّلٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ فِي الصَّلَاتَيْنِ كِلْتَيْهِمَا كَمَا قَالَ سُفْيَانُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Sufyan] dari [Mukhawwal bin Rasyid] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa biasanya Nabi shallallahu 'alaihi wasallam ketika mengerjakan shalat Shubuh pada hari Jum'at, beliau membaca: \"ALIF LAAM MIIM TANZIIL\" (surat As Sajadah) dan, \"HAL ATAA 'ALAL INSAANI HIINUM MINAD DAHRI\" (surat Al Insan). Dan dalam shalat Jum'at beliau membaca surat Al Jumu'ah dan surat Al Munafiqun. Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] -dalam jalur lain- dan Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] keduanya dari [Sufyan] dengan isnad ini. Dan telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mukhawwal] dengan sanad-sanad ini semisalnya pada dua shalat, sebagaimana yang dikatakan Sufyan."},{"p":"Muslim","n":4279,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ نَزَلَتْ عَلَيْهِ سُورَةُ الْجُمُعَةِ فَلَمَّا قَرَأَ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ رَجُلٌ مَنْ هَؤُلَاءِ يَا رَسُولَ اللَّهِ فَلَمْ يُرَاجِعْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى سَأَلَهُ مَرَّةً أَوْ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ وَفِينَا سَلْمَانُ الْفَارِسِيُّ قَالَ فَوَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى سَلْمَانَ ثُمَّ قَالَ لَوْ كَانَ الْإِيمَانُ عِنْدَ الثُّرَيَّا لَنَالَهُ رِجَالٌ مِنْ هَؤُلَاءِ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami ['Abdul 'Aziz] yaitu Ibnu Muhammad dari [Tsaur] dari [Abu Al Ghaits] dari [Abu Hurairah] dia berkata; \"Ketika kami sedang duduk di sisi Rasulullah shallallahu 'alaihi wasallam, tiba-tiba surat Al Jumu'ah diturunkan kepada beliau. Pada saat Rasulullah shallallahu 'alaihi wasallam membacakan ayat yang berbunyi: '…dan orang-orang lain dari mereka yang beIum berhubungan dengan mereka' tiba-tiba ada seseorang yang bertanya; 'Ya Rasulullah, siapakah mereka itu? ' Rasulullah shallallahu 'alaihi wasallam tidak menjawab hingga orang tersebut menanyakannya sebanyak tiga kali. Kebetulan pada saat itu di tengah kami ada Salman Al Farisi. Kemudian Rasulullah meletakkan tangannya pada Salman seraya bersabda: 'Seandainya iman itu berada di tempat bintang-bintang di langit, tentu orang-orang Persia pasti akan mencapainya.'"},{"p":"Nasa'i","n":1371,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَدَخَلَ الْمَسْجِدَ وَعَبْدُ الرَّحْمَنِ ابْنُ أُمِّ الْحَكَمِ يَخْطُبُ قَاعِدًا فَقَالَ انْظُرُوا إِلَى هَذَا يَخْطُبُ قَاعِدًا وَقَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","trj":"Telah mengabarkan kepada kami [Ahmad bin 'Abdullah bin Al Hakam] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari ['Amr bin Murrah] dari [Abu 'Ubaidah] dari [Ka'b bin 'Ujrah] dia berkata; \"Aku masuk ke masjid, dan Abdurrahman bin Ummu Hakam sedang khutbah sambil duduk.\" Lalu Ka'ab berkata; \"Lihatlah orang ini yang sedang khutbah sambil duduk! Padahal Allah Azza wa Jalla berfirman: \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhutbah) '. (Qs. Al Jumu'ah (62): 11).\""},{"p":"Nasa'i","n":1395,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مُخَوَّلٌ قَالَ سَمِعْتُ مُسْلِمًا الْبَطِينَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ يَوْمَ الْجُمُعَةِ فِي صَلَا��ِ الصُّبْحِ الم تَنْزِيلُ وَ هَلْ أَتَى عَلَى الْإِنْسَانِ وَفِي صَلَاةِ الْجُمُعَةِ بِسُورَةِ الْجُمُعَةِ وَالْمُنَافِقِينَ","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la Ash-Shan'ani] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Makhawwal] dia berkata; Aku mendengar [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at saat shalat Subuh membaca Alif Lam Mim Tanziil (surat As-Sajadah) dan Hal Ataa 'Alal Insaan (surah Al Insaan). Sedangkan pada shalat Jum'at beliau membaca surah Al Jumu'ah dan surah Al Munaafiquun."},{"p":"Nasa'i","n":1397,"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍ مَاذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ قَالَ كَانَ يَقْرَأُ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","trj":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Dhamrah bin Sa'id] dari ['Ubaidullah bin 'Abdullah] bahwasanya Adh Dhahhak bin Qais bertanya kepada [An Nu'man bin Basyir] \"Apa yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at, sesudah membaca surah Al Jumu'ah?\" Ia menjawab: \"Beliau membaca surah Al Ghaasyiyah (Hal ataaka hadiitsul ghasyiyah).\""},{"p":"Tirmidzi","n":477,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ وَخَرَجَ إِلَى مَكَّةَ فَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ سُورَةَ الْجُمُعَةِ وَفِي السَّجْدَةِ الثَّانِيَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ عُبَيْدُ اللَّهِ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ فَقُلْتُ لَهُ تَقْرَأُ بِسُورَتَيْنِ كَانَ عَلِيٌّ يَقْرَأُ بِهِمَا بِالْكُوفَةِ قَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَاقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَالنُّعْمَانِ بْنِ بَشِيرٍ وَأَبِي عِنَبَةَ الْخَوْلَانِيِّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ عُبَيْدُ اللَّهِ بْنُ أَبِي رَافِعٍ كَاتِبُ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [bapaknya] dari ['Ubaidullah bin Abu Rafi'] budaknya Rasulullah Shallahu 'alaihi wa sallam dia berkata, Marwan mengangkat Abu Hurairah menjadi gubernur Madinah, dan dia keluar menuju Makkah maka Abu Hurairah shalat Jum'at bersama kami dan membaca surat Al Jumu'ah dan dalam sujud yang kedua dia membaca surat Idza ja'akal Munafiqun, 'Ubaidullah berkata, maka saya menemui Abu Hurairah lalu saya bertanya padanya, kamu membaca dua surat yang dibaca oleh Ali di Kufah?, [Abu Hurairah] menjawab, sesungguhnya saya telah mendengar Rasulullah Shallahu 'alaihi wa sallam membaca keduanya. (perawi) berkata, dan dalam bab ini (ada juga riwayat -pent) dari Ibnu Abbas, An Nu'man bin Basyir dan Abu 'Inabah Al Khqulani. Abu Isa berkata, hadits Abu Hurairah adalah hadits hasan shahih, dan telah diriwayatkan dari Nabi Shallahu 'alaihi wa sallam bahwa beliau membaca dalam shalat Jum'at dengan SABBIHISMA RABBIKAL 'A'LA dan HAL ATAAKA HADIITSUL GHAASYIYAH. 'Ubaidullah bin Abu Rafi' adalah sekretarisnya Ali bin Abu Thalib radliallahu 'anhu."},{"p":"Tirmidzi","n":3061,"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَنِي ثَوْرُ بْنُ زَيْدٍ الدِّيْلِيُّ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ سُورَةُ الْجُمُعَةِ فَتَلَاهَا فَلَمَّا بَلَغَ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ مَنْ هَؤُلَاءِ الَّذِينَ لَمْ يَلْحَقُوا بِنَا فَلَمْ يُكَلِّمْهُ قَالَ وَسَلْمَانُ الْفَارِسِيُّ فِينَا قَالَ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَلْمَانَ يَدَهُ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ كَانَ الْإِيمَانُ بِالثُّرَيَّا لَتَنَاوَلَهُ رِجَالٌ مِنْ هَؤُلَاءِثَوْرُ بْنُ زَيْدٍ مَدَنِيٌّ وَثَوْرُ بْنُ يَزِيدَ شَامِيٌّ وَأَبُو الْغَيْثِ اسْمُهُ سَالِمٌ مَوْلَى عَبْدِ اللَّهِ بْنِ مُطِيعٍ مَدَنِيٌّ ثِقَةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَعَبْدُ اللَّهِ بْنُ جَعْفَرٍ هُوَ وَالِدُ عَلِيِّ بْنِ الْمَدِينِيِّ ضَعَّفَهُ يَحْيَى بْنُ مَعِينٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ","trj":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Abdullah bin Ja'far] telah menceritakan kepadaku [Tsaur bin Zaid Ad Dili] dari [Abu Al Ghaits] dari [Abu Hurairah], ia berkata; kami berada di sisi Rasulullah shallallahu 'alaihi wasallam ketika telah diturunkan Surat Al Jumu'ah, kemudian beliau membacanya. Tatkala beliau telah sampai pada perkataan: \"Dan (juga) kepada kaum yang lain dari mereka yang belum berhubungan dengan mereka. Dan Dia-lah Yang Maha Perkasa lagi Maha Bijaksana.\" (QS. Aljumah 3), Seorang laki-laki berkata; wahai Rasulullah, siapakah mereka yang belum berhubungan dengan kita? Kemudian beliau tidak menjawab sementara Salman Al Farisi bersama kami. Abu Hurairah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya kepada Salman dan berkata: \"Demi Dzat yang jiwaku ada di tanganNya, seandainya keimanan itu berada di gugusan bintang, niscaya akan diambil oleh orang-orang. Diantara mereka adalah Tsaur bin Zaid Madani, dan Tsaur bin Yazid Syami, Abu Al Ghaits namanya adalah Salim mantan budak Abdullah bin Muthi' Madani, yang ia adalah orang yang tsiqah.\" Abu Isa berkata; hadits ini adalah hadits gharib, dan Abdullah bin Ja'far adalah ayah Ali bin Al Madini, ia telah didha'ifkan oleh Yahya bin Ma'in. Dan hadits ini telah diriwayatkan dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dari selain sisi ini."},{"p":"Tirmidzi","n":3603,"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَنِي ثَوْرُ بْنُ زَيْدٍ الدِّيْلِيُّ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ سُورَةُ الْجُمُعَةِ فَتَلَاهَا فَلَمَّا بَلَغَ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ مَنْ هَؤُلَاءِ الَّذِينَ لَمْ يَلْحَقُوا بِنَا فَلَمْ يُكَلِّمْهُ قَالَ وَسَلْمَانُ الْفَارِسِيُّ فِينَا قَالَ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى سَلْمَانَ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ كَانَ الْإِيمَانُ بِالثُّرَيَّا لَتَنَاوَلَهُ رِجَالٌ مِنْ هَؤُلَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو الْغَيْثِ اسْمُهُ سَالِمٌ مَوْلَى عَبْدِ اللَّهِ بْنِ مُطِيعٍ مَدَنِيٌّ","trj":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Abdullah bin Ja'far] telah menceritakan kepadaku [Tsaur bin Zaid Ad Diili] dari [Abu Al Ghaits] dari [Abu Hurairah] dia berkata; \"Ketika kami berada di sisi Rasulullah shallallahu 'alaihi wasallam yaitu ketika turunnya surat Al Jumu'ah, maka beliau membacanya hingga ketika beliau sampai pada ayat Dan (juga) kepada kaum yang lain dari mereka yang belum berhubungan dengan mereka QS Al Jum'ah; 2. maka ada seorang laki-laki bertanya kepada beliau; \"Wahai Rasulullah, siapakah mereka yang belum berhubungan dengan kami?\" beliau tidak menjawabnya, Abu Hurairah berkata; \"Saat itu Salman Al Farisi berada di antara kami.\" Abu Hurairah melanjutkan; Kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya kepada Salman seraya bersabda: \"Sekiranya iman itu di perbintangan, sungguh iman itu akan diraih oleh mereka.\" Abu Isa berkata; \"Hadits ini adalah hadits hasan, dan telah diriwayatkan dari beberapa jalur dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam, adapun Abu Al Ghaits nama aslinya adalah Salim mantan budak (yang telah dimerdekakan oleh) Abdullah bin Muthi' Madani.\" "}]};
